#!/usr/bin/env python3
"""Cross-terminal benchmark harness: runs the workloads generated by
`gen_workloads.py` through rusty_term and any other installed terminal
emulators (ghostty, alacritty, kitty, wezterm, foot, xterm, konsole — see
`terminals.json`), timing each end to end.

Methodology (read this before trusting the numbers):

  For each (terminal, workload) pair, the harness launches the terminal
  fresh, pointed at a shell that runs `cat <workload file>; exit`, and times
  the whole process from spawn to exit. This is the same approach tools like
  `hyperfine` use for full-process benchmarks: `--warmup` iterations are run
  and discarded first, so steady-state numbers aren't dominated by window
  creation / font loading / first-run cache effects.

  What this actually measures is how long it takes the terminal to read and
  keep up with a burst of VT output large enough that the kernel's PTY
  buffer (tens of KB) can't just absorb it — i.e. read+parse+redraw
  throughput under backpressure. It is a solid proxy for "does this terminal
  keep up with `cat`-ing a big file / a noisy build / a busy TUI app", but it
  is NOT a measurement of true pixel-level frame latency, and some renderers
  may report the child as exited slightly before the last frame is actually
  on screen (double-buffered/vsync-throttled paint loops). Two different
  terminals both "finishing fast" doesn't mean their frames looked identical
  along the way.

  rusty_term's TUI/passthrough mode relays to its own stdout rather than
  opening a window, so it needs a real controlling PTY on stdin to enter raw
  mode — the harness allocates one itself (`mode: "pty"` in terminals.json).
  Windowed terminals (including `rusty_term --gui`) are plain subprocesses;
  when $DISPLAY/$WAYLAND_DISPLAY isn't set and `xvfb-run` is available, X11
  terminals are automatically wrapped in it.

Usage:
    python3 bench/gen_workloads.py            # once, or after editing workloads
    python3 bench/run_bench.py                # run everything installed
    python3 bench/run_bench.py --list         # just show what would run
    python3 bench/run_bench.py -t rusty_term -t alacritty -w ascii_throughput
    python3 bench/run_bench.py --iterations 10 --warmup 2 --report bench/results.md
"""

import argparse
import json
import os
import shlex
import shutil
import statistics
import subprocess
import sys
import time

try:
    import pty as pty_mod
except ImportError:
    pty_mod = None  # Windows: pty-mode terminals just won't be runnable.

import threading

BENCH_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ROOT = os.path.dirname(BENCH_DIR)
DEFAULT_WORKLOAD_DIR = os.path.join(BENCH_DIR, "workloads")
DEFAULT_TERMINALS_FILE = os.path.join(BENCH_DIR, "terminals.json")


class Skip(Exception):
    """Raised to skip a terminal entirely (missing binary, no display, ...)."""


def load_terminals(path):
    with open(path) as f:
        data = json.load(f)
    return data["terminals"]


def resolve_binary(term):
    """Find the executable for a terminal entry, or raise Skip."""
    tid = term["id"]
    if tid.startswith("rusty_term"):
        override = os.environ.get("RUSTY_TERM_BIN")
        if override:
            if os.path.isfile(override) and os.access(override, os.X_OK):
                return override
            raise Skip(f"$RUSTY_TERM_BIN={override!r} is not an executable file")
        for cand in ("target/release/rusty_term", "target/debug/rusty_term"):
            path = os.path.join(REPO_ROOT, cand)
            if os.path.isfile(path) and os.access(path, os.X_OK):
                return path
    found = shutil.which(term["binary"])
    if found:
        return found
    raise Skip(f"`{term['binary']}` not found on PATH (and no target/{{release,debug}} build)")


def resolve_display_wrapper(term):
    """Return an argv prefix (possibly empty) to get a display for a
    windowed terminal, or raise Skip if none is available."""
    if not term.get("needs_display"):
        return []
    if os.environ.get("DISPLAY") or os.environ.get("WAYLAND_DISPLAY"):
        return []
    xvfb = shutil.which("xvfb-run")
    if xvfb:
        return [xvfb, "-a"]
    raise Skip("needs a display (X11/Wayland) — set $DISPLAY, or install xvfb-run")


def build_argv(term, binary, wrapper, shell_cmd):
    args = term.get("args", [])
    filled = [shell_cmd if a == "{cmd}" else a for a in args]
    return wrapper + [binary] + filled


def run_subprocess(argv, timeout):
    t0 = time.perf_counter()
    proc = subprocess.Popen(
        argv,
        stdin=subprocess.DEVNULL,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
    )
    try:
        proc.wait(timeout=timeout)
    except subprocess.TimeoutExpired:
        proc.kill()
        proc.wait()
        raise TimeoutError(f"timed out after {timeout}s")
    return time.perf_counter() - t0


def run_pty(argv, timeout):
    """Run argv[0](argv[1:]) attached to a fresh PTY as its controlling
    terminal (needed for programs that call tcgetattr/raw-mode on their own
    stdin). A background thread drains the master side continuously —
    without that, the child can block writing to a full kernel PTY buffer
    and the whole thing deadlocks."""
    if pty_mod is None:
        raise Skip("PTY mode isn't available on this platform")
    pid, master_fd = pty_mod.fork()
    if pid == 0:  # child
        try:
            os.execvp(argv[0], argv)
        except OSError as e:
            os.write(2, f"exec failed: {e}\n".encode())
        os._exit(127)

    stop = threading.Event()

    def drain():
        while not stop.is_set():
            try:
                chunk = os.read(master_fd, 65536)
                if not chunk:
                    return
            except OSError:
                return

    drainer = threading.Thread(target=drain, daemon=True)
    t0 = time.perf_counter()
    drainer.start()

    deadline = t0 + timeout
    while True:
        done_pid, _status = os.waitpid(pid, os.WNOHANG)
        if done_pid == pid:
            break
        if time.perf_counter() > deadline:
            try:
                os.kill(pid, 9)
                os.waitpid(pid, 0)
            except OSError:
                pass
            stop.set()
            try:
                os.close(master_fd)
            except OSError:
                pass
            raise TimeoutError(f"timed out after {timeout}s")
        time.sleep(0.002)

    elapsed = time.perf_counter() - t0
    stop.set()
    try:
        os.close(master_fd)
    except OSError:
        pass
    return elapsed


def run_direct(binary, workload_path, timeout):
    """`mode: "direct"` — run the binary on the workload file with no shell
    wrapper (used for the `cat` baseline)."""
    return run_subprocess([binary, workload_path], timeout)


def run_once(term, binary, wrapper, workload_path, timeout):
    mode = term["mode"]
    if mode == "direct":
        return run_direct(binary, workload_path, timeout)
    shell_cmd = f"cat {shlex.quote(workload_path)}; exit"
    argv = build_argv(term, binary, wrapper, shell_cmd)
    if mode == "pty":
        return run_pty(argv, timeout)
    if mode == "subprocess":
        return run_subprocess(argv, timeout)
    raise ValueError(f"unknown mode {mode!r} for terminal {term['id']!r}")


def discover_workloads(workload_dir, names):
    if not os.path.isdir(workload_dir):
        return {}
    found = {}
    for fname in sorted(os.listdir(workload_dir)):
        if fname.endswith(".vt"):
            found[fname[:-3]] = os.path.join(workload_dir, fname)
    if names:
        return {k: v for k, v in found.items() if k in names}
    return found


def fmt_ms(seconds):
    return f"{seconds * 1000:.1f}"


def bench_terminal_workload(term, binary, wrapper, workload_path, iterations, warmup, timeout, log):
    samples = []
    for i in range(warmup + iterations):
        try:
            elapsed = run_once(term, binary, wrapper, workload_path, timeout)
        except TimeoutError as e:
            log(f"    iter {i + 1}: TIMEOUT ({e})")
            continue
        kind = "warmup" if i < warmup else "timed"
        log(f"    iter {i + 1} [{kind}]: {fmt_ms(elapsed)} ms")
        if i >= warmup:
            samples.append(elapsed)
    if not samples:
        return {"ok": False, "error": "all iterations failed/timed out"}
    size = os.path.getsize(workload_path)
    return {
        "ok": True,
        "samples_s": samples,
        "median_s": statistics.median(samples),
        "mean_s": statistics.mean(samples),
        "stdev_s": statistics.stdev(samples) if len(samples) > 1 else 0.0,
        "bytes": size,
        "mb_per_s": (size / 1_000_000) / statistics.median(samples) if statistics.median(samples) > 0 else float("inf"),
    }


def write_json(results, path):
    with open(path, "w") as f:
        json.dump(results, f, indent=2)


def write_markdown(results, terminal_order, workload_order, path):
    lines = []
    lines.append("# rusty_term cross-terminal benchmark results\n")
    lines.append(
        "Median wall-clock time (ms) per workload, full-process launch to "
        "exit, warmup iterations excluded. Lower is better. See "
        "`bench/README.md` for methodology and caveats.\n"
    )
    header = "| Workload | " + " | ".join(terminal_order) + " |"
    sep = "|---|" + "---|" * len(terminal_order)
    lines.append(header)
    lines.append(sep)
    for wl in workload_order:
        row = [wl]
        for tid in terminal_order:
            cell = results.get(tid, {}).get(wl)
            if cell is None:
                row.append("—")
            elif not cell.get("ok"):
                row.append("error")
            else:
                row.append(f"{fmt_ms(cell['median_s'])} ± {fmt_ms(cell['stdev_s'])}")
        lines.append("| " + " | ".join(row) + " |")
    lines.append("")
    lines.append("## Throughput summary (median MB/s across workloads)\n")
    lines.append("| Terminal | MB/s |")
    lines.append("|---|---|")
    for tid in terminal_order:
        rates = [
            results[tid][wl]["mb_per_s"]
            for wl in workload_order
            if results.get(tid, {}).get(wl, {}).get("ok")
        ]
        if rates:
            lines.append(f"| {tid} | {statistics.median(rates):.1f} |")
        else:
            lines.append(f"| {tid} | — |")
    with open(path, "w") as f:
        f.write("\n".join(lines) + "\n")


def main():
    ap = argparse.ArgumentParser(description=__doc__, formatter_class=argparse.RawDescriptionHelpFormatter)
    ap.add_argument("-t", "--terminal", action="append", dest="terminals", help="terminal id to run (repeatable); default: all in terminals.json")
    ap.add_argument("-w", "--workload", action="append", dest="workloads", help="workload name to run (repeatable); default: all found in bench/workloads")
    ap.add_argument("--terminals-file", default=DEFAULT_TERMINALS_FILE)
    ap.add_argument("--workload-dir", default=DEFAULT_WORKLOAD_DIR)
    ap.add_argument("--iterations", type=int, default=5, help="timed iterations per (terminal, workload) pair")
    ap.add_argument("--warmup", type=int, default=1, help="untimed warmup iterations, discarded")
    ap.add_argument("--timeout", type=float, default=30.0, help="per-iteration timeout in seconds")
    ap.add_argument("--out", default=os.path.join(BENCH_DIR, "results.json"), help="path to write raw JSON results")
    ap.add_argument("--report", default=os.path.join(BENCH_DIR, "results.md"), help="path to write the Markdown report")
    ap.add_argument("--list", action="store_true", help="show which terminals/workloads would run and exit, without benchmarking")
    ap.add_argument("-q", "--quiet", action="store_true", help="only print per-terminal summaries, not per-iteration timings")
    args = ap.parse_args()

    def log(msg):
        if not args.quiet:
            print(msg)

    all_terms = load_terminals(args.terminals_file)
    if args.terminals:
        wanted = set(args.terminals)
        unknown = wanted - {t["id"] for t in all_terms}
        if unknown:
            sys.exit(f"unknown terminal id(s): {', '.join(sorted(unknown))}")
        all_terms = [t for t in all_terms if t["id"] in wanted]

    workloads = discover_workloads(args.workload_dir, set(args.workloads) if args.workloads else None)
    if not workloads:
        sys.exit(
            f"no workload files found in {args.workload_dir} — run "
            "`python3 bench/gen_workloads.py` first"
        )

    # Resolve availability up front so --list and the run share one path.
    resolved = []
    for term in all_terms:
        try:
            binary = resolve_binary(term)
            wrapper = resolve_display_wrapper(term)
            resolved.append((term, binary, wrapper, None))
        except Skip as e:
            resolved.append((term, None, None, str(e)))

    print(f"Workloads ({len(workloads)}): {', '.join(sorted(workloads))}\n")
    print("Terminals:")
    for term, binary, wrapper, skip_reason in resolved:
        if skip_reason:
            print(f"  [skip] {term['id']:20s} {skip_reason}")
        else:
            wrap_note = f" (via {' '.join(wrapper)})" if wrapper else ""
            print(f"  [ ok ] {term['id']:20s} {binary}{wrap_note}")
    print()

    if args.list:
        return

    workload_order = sorted(workloads)
    terminal_order = [term["id"] for term, _b, _w, skip_reason in resolved if skip_reason is None]
    results = {}

    for term, binary, wrapper, skip_reason in resolved:
        tid = term["id"]
        if skip_reason:
            continue
        results[tid] = {}
        print(f"=== {term['label']} ({tid}) ===")
        for wl in workload_order:
            path = workloads[wl]
            log(f"  {wl} ({os.path.getsize(path)} bytes)")
            outcome = bench_terminal_workload(
                term, binary, wrapper, path, args.iterations, args.warmup, args.timeout, log
            )
            results[tid][wl] = outcome
            if outcome["ok"]:
                print(
                    f"  {wl:22s} median {fmt_ms(outcome['median_s']):>8} ms "
                    f"± {fmt_ms(outcome['stdev_s']):>6} ms  "
                    f"({outcome['mb_per_s']:.1f} MB/s)"
                )
            else:
                print(f"  {wl:22s} FAILED: {outcome['error']}")
        print()

    write_json(results, args.out)
    write_markdown(results, terminal_order, workload_order, args.report)
    print(f"Wrote {args.out}")
    print(f"Wrote {args.report}")


if __name__ == "__main__":
    main()
